    <span style="color:#8b008b;font-weight:bold">background</span>:<span style="color:#8b008b;font-weight:bold">-webkit-</span><span style="color:#658b00">linear-gradient</span>(<span style="color:#8b008b;font-weight:bold">top</span>,<span style="color:#b452cd">#d1d4d3</span> <span style="color:#b452cd">0</span><span style="color:#00688b;font-weight:bold">%</span>,<span style="color:#b452cd">#c4c7c8</span> <span style="color:#b452cd">100</span><span style="color:#00688b;font-weight:bold">%</span>);
    <span style="color:#8b008b;font-weight:bold">background</span>:<span style="color:#8b008b;font-weight:bold">-moz-</span><span style="color:#658b00">linear-gradient</span>(<span style="color:#8b008b;font-weight:bold">top</span>,<span style="color:#b452cd">#d1d4d3</span> <span style="color:#b452cd">0</span><span style="color:#00688b;font-weight:bold">%</span>,<span style="color:#b452cd">#c4c7c8</span> <span style="color:#b452cd">100</span><span style="color:#00688b;font-weight:bold">%</span>);
    <span style="color:#8b008b;font-weight:bold">color</span>:<span style="color:#b452cd">#111c24</span>;

}

