</code></pre></div><p>2.Alert</p>
<p>Alert 主要是模拟了界面，并显示提示信息。JS 代码.Demo 可查看：<a href="http://wewoor.github.io/CNUI/document.html">http://wewoor.github.io/CNUI/document.html</a> 。</p>
<div class="highlight"><pre style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4"><code class="language-javascript" data-lang="javascript"><span style="color:#228b22">//Alert
</span><span style="color:#228b22"></span><span style="color:#8b008b;font-weight:bold">var</span> Alert = {

    func : <span style="color:#8b008b;font-weight:bold">function</span>(){},
    name : <span style="color:#cd5555">&#34;dialog&#34;</span>,
    show : <span style="color:#8b008b;font-weight:bold">function</span>(msg){        <span style="color:#228b22">//show function
</span><span style="color:#228b22"></span>        <span style="color:#8b008b;font-weight:bold">var</span> confirm = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;div&#34;</span>);
            confirm.className = <span style="color:#8b008b;font-weight:bold">this</span>.name;
            confirm.id = <span style="color:#8b008b;font-weight:bold">this</span>.name;;
        <span style="color:#8b008b;font-weight:bold">var</span> confirmHeader = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;div&#34;</span>);
            confirmHeader.className = <span style="color:#cd5555">&#34;dialog-header&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> headerSpan = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;span&#34;</span>);
            headerSpan.className = <span style="color:#cd5555">&#34;dialog-title&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> confirmContent = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;div&#34;</span>);
            confirmContent.className = <span style="color:#cd5555">&#34;dialog-content&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> contentSpan = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;span&#34;</span>);
            contentSpan.className = <span style="color:#cd5555">&#34;content-main alert-content&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> contentBtnDiv = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;div&#34;</span>);
            contentBtnDiv.className=<span style="color:#cd5555">&#34;content-btn&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> btnConfirm = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;a&#34;</span>);    <span style="color:#228b22">//确认按钮
</span><span style="color:#228b22"></span>            btnConfirm.href = <span style="color:#cd5555">&#34;javascript:Alert.hide()&#34;</span>;
            btnConfirm.className = <span style="color:#cd5555">&#34;btn alert&#34;</span>;

        <span style="color:#228b22">//按钮添加
</span><span style="color:#228b22"></span>        contentBtnDiv.appendChild(btnConfirm);

        confirmContent.appendChild(contentSpan);
        confirmContent.appendChild(contentBtnDiv);

        confirmHeader.appendChild(headerSpan);

        confirm.appendChild(confirmHeader);
        confirm.appendChild(confirmContent);

        <span style="color:#228b22">//default button
</span><span style="color:#228b22"></span>        headerSpan.innerHTML = <span style="color:#cd5555">&#34;警示框！&#34;</span>;
        btnConfirm.innerHTML = <span style="color:#cd5555">&#34;确认&#34;</span>;
        contentSpan.innerHTML = <span style="color:#cd5555">&#34;这是一个警示框！&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">if</span>(msg != <span style="color:#8b008b;font-weight:bold">null</span> &amp;&amp; msg != <span style="color:#8b008b;font-weight:bold">undefined</span>){
            contentSpan.innerHTML = msg;
        }

        <span style="color:#658b00">document</span>.body.appendChild(confirm);
        <span style="color:#8b008b;font-weight:bold">return</span> confirm;
    },
    hide : <span style="color:#8b008b;font-weight:bold">function</span>(){
        <span style="color:#8b008b;font-weight:bold">var</span> confirm = <span style="color:#658b00">document</span>.getElementById(<span style="color:#8b008b;font-weight:bold">this</span>.name);
        <span style="color:#8b008b;font-weight:bold">if</span>(confirm != <span style="color:#8b008b;font-weight:bold">null</span> &amp;&amp; confirm != <span style="color:#8b008b;font-weight:bold">undefined</span>){
            <span style="color:#658b00">document</span>.body.removeChild(confirm);
        }
    }
}
</code></pre></div><p>3.Confirm 组件</p>
<p>confirm 对话框并没有像原生的 confirm 组件返回 true 或者 false，而是点击确认按钮后执行了传入的回调函数，点击取消按钮则移除了这个组件。demo 请看：<a href="http://wewoor.github.io/CNUI/document.html">http://wewoor.github.io/CNUI/document.html</a></p>
<div class="highlight"><pre style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4"><code class="language-javascript" data-lang="javascript"><span style="color:#228b22">//Confirm
</span><span style="color:#228b22"></span><span style="color:#8b008b;font-weight:bold">var</span>  Confirm = {
    func : <span style="color:#8b008b;font-weight:bold">function</span>(){},
    name : <span style="color:#cd5555">&#34;dialog&#34;</span>,
    show : <span style="color:#8b008b;font-weight:bold">function</span>(msg,call){        <span style="color:#228b22">//show function
</span><span style="color:#228b22"></span>        <span style="color:#8b008b;font-weight:bold">var</span> confirm = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;div&#34;</span>);
            confirm.className = <span style="color:#8b008b;font-weight:bold">this</span>.name;
            confirm.id = <span style="color:#8b008b;font-weight:bold">this</span>.name;;
        <span style="color:#8b008b;font-weight:bold">var</span> confirmHeader = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;div&#34;</span>);
            confirmHeader.className = <span style="color:#cd5555">&#34;dialog-header&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> headerSpan = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;span&#34;</span>);
            headerSpan.className = <span style="color:#cd5555">&#34;dialog-title&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> confirmContent = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;div&#34;</span>);
            confirmContent.className = <span style="color:#cd5555">&#34;dialog-content&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> contentSpan = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;span&#34;</span>);
            contentSpan.className = <span style="color:#cd5555">&#34;content-main&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> contentBtnDiv = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;div&#34;</span>);
            contentBtnDiv.className=<span style="color:#cd5555">&#34;content-btn&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> btnConfirm = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;a&#34;</span>);    <span style="color:#228b22">//确认按钮
</span><span style="color:#228b22"></span>            btnConfirm.href = <span style="color:#cd5555">&#34;javascript:Confirm.callback()&#34;</span>;
            btnConfirm.className = <span style="color:#cd5555">&#34;btn&#34;</span>;
        <span style="color:#8b008b;font-weight:bold">var</span> btnCancle = <span style="color:#658b00">document</span>.createElement(<span style="color:#cd5555">&#34;a&#34;</span>);    <span style="color:#228b22">//取消按钮
</span><span style="color:#228b22"></span>            btnCancle.className = <span style="color:#cd5555">&#34;btn&#34;</span>;
            btnCancle.href = <span style="color:#cd5555">&#34;javascript:Confirm.hide()&#34;</span>;

        <span style="color:#228b22">//按钮添加
</span><span style="color:#228b22"></span>        contentBtnDiv.appendChild(btnConfirm);
        contentBtnDiv.appendChild(btnCancle);

        confirmContent.appendChild(contentSpan);
        confirmContent.appendChild(contentBtnDiv);

        confirmHeader.appendChild(headerSpan);

        confirm.appendChild(confirmHeader);
        confirm.appendChild(confirmContent);

        <span style="color:#228b22">//default style
</span><span style="color:#228b22"></span>        headerSpan.innerHTML = <span style="color:#cd5555">&#34;对话框&#34;</span>;
        contentSpan.innerHTML = <span style="color:#cd5555">&#34;这是确认对话框？&#34;</span>;
        btnConfirm.innerHTML = <span style="color:#cd5555">&#34;确认&#34;</span>;
        btnCancle.innerHTML = <span style="color:#cd5555">&#34;取消&#34;</span>;

        <span style="color:#228b22">//if the property html is not null and not undefined
</span><span style="color:#228b22"></span>        <span style="color:#228b22">//just set this property.
</span><span style="color:#228b22"></span>        <span style="color:#8b008b;font-weight:bold">if</span>(msg != <span style="color:#8b008b;font-weight:bold">undefined</span>){
            contentSpan.innerHTML = msg;
        }

        <span style="color:#228b22">//set callback
</span><span style="color:#228b22"></span>        <span style="color:#8b008b;font-weight:bold">if</span>(call != <span style="color:#8b008b;font-weight:bold">null</span> &amp;&amp; call != <span style="color:#8b008b;font-weight:bold">undefined</span>){
            <span style="color:#8b008b;font-weight:bold">if</span>(<span style="color:#8b008b;font-weight:bold">typeof</span>(call) == <span style="color:#cd5555">&#34;function&#34;</span>){
                <span style="color:#8b008b;font-weight:bold">this</span>.func = call;
            }
        }

        <span style="color:#658b00">document</span>.body.appendChild(confirm);
        <span style="color:#8b008b;font-weight:bold">return</span> confirm;
    },

    hide : <span style="color:#8b008b;font-weight:bold">function</span>(){
        <span style="color:#8b008b;font-weight:bold">var</span> confirm = <span style="color:#658b00">document</span>.getElementById(<span style="color:#8b008b;font-weight:bold">this</span>.name);
        <span style="color:#8b008b;font-weight:bold">if</span>(confirm != <span style="color:#8b008b;font-weight:bold">null</span> &amp;&amp; confirm != <span style="color:#8b008b;font-weight:bold">undefined</span>){
            <span style="color:#658b00">document</span>.body.removeChild(confirm);
        }
    },
    callback : <span style="color:#8b008b;font-weight:bold">function</span>(){
        <span style="color:#228b22">//执行call回调方法
</span><span style="color:#228b22"></span>        <span style="color:#8b008b;font-weight:bold">this</span>.func();
        <span style="color:#228b22">//隐藏confirm对象
</span><span style="color:#228b22"></span>        <span style="color:#8b008b;font-weight:bold">this</span>.hide();
    }
}
</code></pre></div>- //imziv.com/posts/2013/js%E6%A8%A1%E6%8B%9Falert%E4%B8%8Econfirm%E5%AF%B9%E8%AF%9D%E6%A1%86/ - 2012-2020 Ziv小威

让美的事情发生 //imziv.com/posts/2013/%E8%AF%A6%E8%A7%A3css%E6%A0%B7%E5%BC%8F%E7%9A%84position%E5%B1%9E%E6%80%A7/ -<p>平时在写 css 样式的时候 position 是我们比较常用的一个属性。有时候会弄不清其几个属性值的真正区别。不过用的时间久了，也就慢慢的明白了。不过其实想用好 position 有时候还是需要些技巧的。写篇博文总结下自己。</p>
<p>position 的作用：用于设置对 html 元素的定位方式　　
position 属性的值：</p>
<table>
<thead>
<tr>
<th>值名称</th>
<th>描述</th>
</tr>
</thead>
<tbody>
<tr>
<td>static</td>
<td>position 的默认值，设置此属性时，元素按照正常的流式布局往下排列</td>
</tr>
<tr>
<td>inherit</td>
<td>继承父元素的 position 值</td>
</tr>
<tr>
<td>relative</td>
<td>相对于其他元素的定位</td>
</tr>
<tr>
<td>absolute</td>
<td>相对于采用 static 定位的父元素的绝对定位</td>
</tr>
<tr>
<td>fixed</td>
<td>相对于浏览器的绝对定位</td>
</tr>
</tbody>
</table>
<p>备注：如果给元素才用了 top,left 等定位属性时，只有 relative,absolute,fixed 才会有效果。</p>
<p>3.应用实例</p>
<p>　　　这里主要记录是 absolute 和 fixed 属性值。absolute 与 fixed 的好处主要就是它的定位不拘束于其它同级元素，不想其它几种布局自己的定位会被其它元素所影响。所以像做一些动画效果，div 浮动效果的时候，这个两个属性值就尤为适合了。</p>
<p>　　结合 z-index 的使用</p>
<p>　　　　z-index 用于控制元素在页面中层级的位置，就跟高楼大厦的楼层一样，z-index 则可用于控制所在的楼层。absolute 与 fixed 都支持 z-index 属性。所以当几个元素采用 absolute 或者 fixed 属性时，为了达到层次显示的效果，z-index 属性就很方便了。</p>
<p>　　示例：</p>
<div class="highlight"><pre style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4"><code class="language-html" data-lang="html">&lt;<span style="color:#8b008b;font-weight:bold">html</span>&gt;
     &lt;<span style="color:#8b008b;font-weight:bold">title</span>&gt;Position&lt;/<span style="color:#8b008b;font-weight:bold">title</span>&gt;
     &lt;<span style="color:#8b008b;font-weight:bold">head</span>&gt;
      &lt;<span style="color:#8b008b;font-weight:bold">meta</span> <span style="color:#658b00">http-equiv</span>=<span style="color:#cd5555">&#34;Content-Type&#34;</span> <span style="color:#658b00">content</span>=<span style="color:#cd5555">&#34;text/html; charset=utf-8&#34;</span>&gt;
        &lt;<span style="color:#8b008b;font-weight:bold">style</span> <span style="color:#658b00">type</span>=<span style="color:#cd5555">&#34;text/css&#34;</span>&gt;
              #<span style="color:#008b45;text-decoration:underline">container</span>{
                  <span style="color:#8b008b;font-weight:bold">height</span>:<span style="color:#b452cd">1000</span><span style="color:#00688b;font-weight:bold">px</span>;
                  <span style="color:#8b008b;font-weight:bold">width</span>: <span style="color:#b452cd">960</span><span style="color:#00688b;font-weight:bold">px</span>;
                  <span style="color:#8b008b;font-weight:bold">margin</span>: <span style="color:#8b008b;font-weight:bold">auto</span>;
                  <span style="color:#8b008b;font-weight:bold">background-color</span>: <span style="color:#8b008b;font-weight:bold">blue</span>;
              }
              #<span style="color:#008b45;text-decoration:underline">roll-top</span> {
                  <span style="color:#8b008b;font-weight:bold">padding</span>:<span style="color:#b452cd">20</span><span style="color:#00688b;font-weight:bold">px</span>;
                  <span style="color:#8b008b;font-weight:bold">background-color</span>:<span style="color:#b452cd">#525252</span>;
                  <span style="color:#8b008b;font-weight:bold">cursor</span>: <span style="color:#8b008b;font-weight:bold">pointer</span>;
                  <span style="color:#8b008b;font-weight:bold">right</span>:<span style="color:#b452cd">10</span><span style="color:#00688b;font-weight:bold">px</span>;

              }
              #<span style="color:#008b45;text-decoration:underline">roll-top</span>,#<span style="color:#008b45;text-decoration:underline">below</span>{
                  <span style="color:#8b008b;font-weight:bold">position</span>:<span style="color:#8b008b;font-weight:bold">fixed</span>;
                  <span style="color:#8b008b;font-weight:bold">top</span>:<span style="color:#b452cd">85</span><span style="color:#00688b;font-weight:bold">%</span>;
                  <span style="color:#8b008b;font-weight:bold">font-size</span>:<span style="color:#b452cd">12</span><span style="color:#00688b;font-weight:bold">px</span>;
                  <span style="color:#8b008b;font-weight:bold">color</span>:<span style="color:#b452cd">#FFFFFF</span>;
              }
              #<span style="color:#008b45;text-decoration:underline">below</span>{
                  <span style="color:#8b008b;font-weight:bold">width</span>:<span style="color:#b452cd">100</span><span style="color:#00688b;font-weight:bold">%</span>;
                  <span style="color:#8b008b;font-weight:bold">height</span>:<span style="color:#b452cd">100</span><span style="color:#00688b;font-weight:bold">px</span>;
                  <span style="color:#8b008b;font-weight:bold">background-color</span>:<span style="color:#b452cd">#757575</span>;
                  <span style="color:#8b008b;font-weight:bold">z-index</span>: <span style="color:#b452cd">-1</span>;
              }
        &lt;/<span style="color:#8b008b;font-weight:bold">style</span>&gt;
        &lt;<span style="color:#8b008b;font-weight:bold">script</span> <span style="color:#658b00">type</span>=<span style="color:#cd5555">&#34;text/javascript&#34;</span>&gt;
          <span style="color:#8b008b;font-weight:bold">function</span> rollbackTop(){
            <span style="color:#658b00">window</span>.scrollTo(<span style="color:#b452cd">0</span>);
          }
        &lt;/<span style="color:#8b008b;font-weight:bold">script</span>&gt;
    &lt;/<span style="color:#8b008b;font-weight:bold">head</span>&gt;
    &lt;<span style="color:#8b008b;font-weight:bold">body</span>&gt;
        &lt;<span style="color:#8b008b;font-weight:bold">div</span> <span style="color:#658b00">id</span>=<span style="color:#cd5555">&#34;container&#34;</span>&gt;
        &lt;/<span style="color:#8b008b;font-weight:bold">div</span>&gt;
        &lt;<span style="color:#8b008b;font-weight:bold">div</span> <span style="color:#658b00">id</span>=<span style="color:#cd5555">&#34;roll-top&#34;</span> <span style="color:#658b00">onclick</span>=<span style="color:#cd5555">&#34;rollbackTop()&#34;</span>&gt;返回顶部&lt;/<span style="color:#8b008b;font-weight:bold">div</span>&gt;
        &lt;<span style="color:#8b008b;font-weight:bold">div</span> <span style="color:#658b00">id</span>=<span style="color:#cd5555">&#34;below&#34;</span>&gt;我在下面&lt;/<span style="color:#8b008b;font-weight:bold">div</span>&gt;
    &lt;/<span style="color:#8b008b;font-weight:bold">body</span>&gt;
    &lt;<span style="color:#8b008b;font-weight:bold">script</span>&gt;&lt;/<span style="color:#8b008b;font-weight:bold">script</span>&gt;
&lt;/<span style="color:#8b008b;font-weight:bold">html</span>&gt;
</code></pre></div><p>像利用 absolute 做动画效果的例子在 JQuery 官方上面的例子还是比较多。再次就不做详解了。</p>
- //imziv.com/posts/2013/%E8%AF%A6%E8%A7%A3css%E6%A0%B7%E5%BC%8F%E7%9A%84position%E5%B1%9E%E6%80%A7/ - 2012-2020 Ziv小威

让美的事情发生 //imziv.com/posts/2013/play-framework%E5%B8%B8%E7%94%A8%E6%A0%87%E7%AD%BElistset%E5%A6%82%E4%BD%95%E9%81%8D%E5%8E%86listmap%E7%B1%BB%E5%9E%8B%E6%95%B0%E6%8D%AE/ -<p>最近一段时间的项目都是在 Play 这个框架上进行开发的，挺强大的，但不足之处也挺多的。今天分享下 play 中强大的标签，遍历 list,map 类型的数据的用法。</p>
<p>遍历单纯的 list 数据,例如：List<!-- raw HTML omitted --> peoples;</p>
<div class="highlight"><pre style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4"><code class="language-java" data-lang="java"><span style="color:#a61717;background-color:#e3d2d2">#</span>{list peoples,as:<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>people<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>} <span style="color:#228b22">//peoples为list对象，people为实体变量名 ，name则为实体相对应的属性值
</span><span style="color:#228b22"></span>    ${people.<span style="color:#658b00">name</span>}
 <span style="color:#a61717;background-color:#e3d2d2">#</span>{/list}
遍历list中泛化的map类型<span style="color:#a61717;background-color:#e3d2d2">，</span>例如<span style="color:#a61717;background-color:#e3d2d2">：</span>List&lt;Map&lt;People&gt;&gt; peoples;
<span style="color:#a61717;background-color:#e3d2d2">#</span>{list peoples,as:<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>people<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>} <span style="color:#228b22">//peoples为list对象，people为实体变量名 ，name则为实体相对应的属性值
</span><span style="color:#228b22"></span>   <span style="color:#a61717;background-color:#e3d2d2">#</span>{list people,as:<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>map<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>}${map.<span style="color:#658b00">value</span>.<span style="color:#658b00">property</span>}<span style="color:#a61717;background-color:#e3d2d2">#</span>{/list}
    <span style="color:#228b22">//第二个list将people再次转换，map取值则像正常的取值，value为map的value,可是对象类型，property则为对象类型的属性值
</span><span style="color:#228b22"></span> <span style="color:#a61717;background-color:#e3d2d2">#</span>{/list}
</code></pre></div><p>遍历单纯的 Map 类型，例如：Map&lt;id,People&gt; people;</p>
<div class="highlight"><pre style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4"><code class="language-java" data-lang="java"><span style="color:#228b22">//如果知道map的key值，则可以直接通过一下方式获取：
</span><span style="color:#228b22"></span>${people.<span style="color:#658b00">get</span>(key).<span style="color:#658b00">name</span>}
<span style="color:#228b22">//如果是要遍历一个map,同样适用list标签
</span><span style="color:#228b22"></span><span style="color:#a61717;background-color:#e3d2d2">#</span>{list people,as:<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>peo<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>}
${peo.<span style="color:#658b00">value</span>.<span style="color:#658b00">name</span>} <span style="color:#228b22">//peo为map变量，value为key的值，name为属性值
</span><span style="color:#228b22"></span><span style="color:#a61717;background-color:#e3d2d2">#</span>{/list}

<span style="color:#228b22">//如果id是一个对象的话，获取其对象的值则可以这样：
</span><span style="color:#228b22"></span><span style="color:#a61717;background-color:#e3d2d2">#</span>{list people,as:<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>peo<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>}
${peo.<span style="color:#658b00">key</span>.<span style="color:#658b00">name</span>} <span style="color:#228b22">//peo为map变量，key为对象，key为实体对象，name为属性值
</span><span style="color:#228b22"></span><span style="color:#a61717;background-color:#e3d2d2">#</span>{/list}
</code></pre></div><p>遍历 map 与 list 的组合，例如：Map&lt;id,List<!-- raw HTML omitted -->&gt; people;</p>
<div class="highlight"><pre style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4"><code class="language-java" data-lang="java"><span style="color:#228b22">//知道ID的情况下可以这样,通过get方法获取对象
</span><span style="color:#228b22"></span><span style="color:#a61717;background-color:#e3d2d2">#</span>{list people.<span style="color:#658b00">get</span>(id),as:<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>peo<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>}
　　${peo.<span style="color:#658b00">name</span>}
<span style="color:#a61717;background-color:#e3d2d2">#</span>{list}
<span style="color:#228b22">//如果people是多个map对象，则可以
</span><span style="color:#228b22"></span><span style="color:#a61717;background-color:#e3d2d2">#</span>{list people,as: <span style="color:#a61717;background-color:#e3d2d2">&#39;</span>map<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>}
　　<span style="color:#a61717;background-color:#e3d2d2">#</span>{list map.<span style="color:#658b00">value</span>,as:<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>people<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>
</code></pre></div><p>set,if,break 标签的使用:</p>
<div class="highlight"><pre style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4"><code class="language-java" data-lang="java"><span style="color:#228b22">//模拟遍历list时的计数器
</span><span style="color:#228b22"></span><span style="color:#a61717;background-color:#e3d2d2">#</span>{set count:0}<span style="color:#228b22">//设置变量count
</span><span style="color:#228b22"></span><span style="color:#a61717;background-color:#e3d2d2">#</span>{list data,as:<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>li<span style="color:#a61717;background-color:#e3d2d2">&#39;</span>}
 　　&lt;h1&gt;${count}&lt;/h1&gt;
    <span style="color:#a61717;background-color:#e3d2d2">#</span>{<span style="color:#8b008b;font-weight:bold">if</span> count == 2}
     　　&lt;% <span style="color:#8b008b;font-weight:bold">break</span> %&gt; <span style="color:#228b22">//跳出
</span><span style="color:#228b22"></span>    <span style="color:#a61717;background-color:#e3d2d2">#</span>{/<span style="color:#8b008b;font-weight:bold">if</span>}
    <span style="color:#a61717;background-color:#e3d2d2">#</span>{ifelse count == 3}
       &lt;h1&gt;${count}&lt;/h1}
    <span style="color:#a61717;background-color:#e3d2d2">#</span>{/ifelse}
    <span style="color:#a61717;background-color:#e3d2d2">#</span>{<span style="color:#8b008b;font-weight:bold">else</span>}
       &lt;h1&gt;${count}&lt;/h1&gt;
    <span style="color:#a61717;background-color:#e3d2d2">#</span>{/<span style="color:#8b008b;font-weight:bold">else</span>}
    <span style="color:#a61717;background-color:#e3d2d2">#</span>{set count:count+1}<span style="color:#228b22">//自增
</span><span style="color:#228b22"></span><span style="color:#a61717;background-color:#e3d2d2">#</span>{/list}
</code></pre></div>- //imziv.com/posts/2013/play-framework%E5%B8%B8%E7%94%A8%E6%A0%87%E7%AD%BElistset%E5%A6%82%E4%BD%95%E9%81%8D%E5%8E%86listmap%E7%B1%BB%E5%9E%8B%E6%95%B0%E6%8D%AE/ - 2012-2020 Ziv小威

让美的事情发生 //imziv.com/posts/2012/fileloder.js+struts2%E5%AE%9E%E7%8E%B0%E6%96%87%E4%BB%B6%E5%BC%82%E6%AD%A5%E4%B8%8A%E4%BC%A0%E6%97%A0%E9%A1%B5%E9%9D%A2%E5%88%B7%E6%96%B0%E6%95%88%E6%9E%9C/ -<h2 id="一前言">一、前言</h2>
<p>　　之前在写一个 web 的文件上传的功能时，希望在 web 前端对文件的大小，及类型用 js 给验证掉，然后提交到服务器保存入数据库，同时要求达到页面无刷新的异步效果。在网上也看到有很多用 iframe 的方式实现了这样的无刷新效果。不过我在这里给大家介绍的是一款 js 插件，非常强大。在用这款插件前，在网上查询了好久关于 js 对文件类型的验证，当然这样的方法很多，大多数通过正则表达式对文件后缀验证的方式，只不过对文件大小验证这项功能上网上贴出的大多数代码都不靠谱，很多浏览器根本就不支持很多属性操作，比喻说 filesize 这项，而且浏览器的兼容性上考虑起来非常麻烦。不过所幸后来我找到了 fileloader.js 这个插件，前身好像是 ajaxfileupload.js，这款插件可通过 js 提交验证文件的大小及类型、支持拖拽上传。有时间把它的源码研究下也跟大家分享下。fileloader.js 官方地址是：&laquo;<a href="http://fineuploader.com/%3E">http://fineuploader.com/&gt;</a>。当然上面也有很多 DEMO&gt;，大家可以自己去看。</p>
<h2 id="二工作准备">二、工作准备</h2>
<p>　　添加 strut2 框架；将下载的 fileloader.js 的文件添加到页面；将 fileloader.css 文件添加到页面；添加 jquery 包。</p>
<h2 id="三html-页面代码">三、HTML 页面代码</h2>
<div class="highlight"><pre style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4"><code class="language-html" data-lang="html">
&lt;<span style="color:#8b008b;font-weight:bold">html</span>&gt;

&lt;<span style="color:#8b008b;font-weight:bold">head</span>&gt;

&lt;<span style="color:#8b008b;font-weight:bold">title</span>&gt;文件上传&lt;/<span style="color:#8b008b;font-weight:bold">title</span>&gt;

&lt;<span style="color:#8b008b;font-weight:bold">link</span> <span style="color:#658b00">href</span>=<span style="color:#cd5555">&#34;css/fileuploader.css&#34;</span> <span style="color:#658b00">rel</span>=<span style="color:#cd5555">&#34;stylesheet&#34;</span> <span style="color:#658b00">type</span>=<span style="color:#cd5555">&#34;text/css&#34;</span> /&gt;

　　&lt;<span style="color:#8b008b;font-weight:bold">script</span> <span style="color:#658b00">language</span>=<span style="color:#cd5555">&#34;javascript&#34;</span> <span style="color:#658b00">type</span>=<span style="color:#cd5555">&#34;text/javascript&#34;</span> <span style="color:#658b00">src</span>=<span style="color:#cd5555">&#34;js/jquery-1.8.0.js&#34;</span>&gt;&lt;/<span style="color:#8b008b;font-weight:bold">script</span>&gt;

　　&lt;<span style="color:#8b008b;font-weight:bold">script</span> <span style="color:#658b00">language</span>=<span style="color:#cd5555">&#34;javascript&#34;</span> <span style="color:#658b00">type</span>=<span style="color:#cd5555">&#34;text/javascript&#34;</span> <span style="color:#658b00">src</span>=<span style="color:#cd5555">&#34;js/fileuploader.js&#34;</span>&gt;&lt;/<span style="color:#8b008b;font-weight:bold">script</span>&gt;
　　&lt;<span style="color:#8b008b;font-weight:bold">script</span> <span style="color:#658b00">language</span>=<span style="color:#cd5555">&#34;javascript&#34;</span> <span style="color:#658b00">type</span>=<span style="color:#cd5555">&#34;text/javascript&#34;</span>&gt;

　　　　$(document).ready(function() {
   　　　　 var thumbnailuploader = new qq.FileUploader({　　　　　　//new fileuploader object
    　　　　  element: $(&#39;#thumbnail-fine-uploader&#39;)[0],　　　　　　//选定页面div元素，这里用了jquery的选择器
   　　　　   action: &#39;service/uploadImage&#39;,　　　　　　　　　　　　//提交的action地址
    　　　　  debug: true,
    　　　　  multiple: false,
    　　　　  allowedExtensions: [&#39;jpeg&#39;, &#39;jpg&#39;, &#39;gif&#39;, &#39;png&#39;],　　//允许上传的文件类型
     　　　　 sizeLimit: 500*1024,　　　　　　　　　　　　　　　　//允许上传文件的大小，这里是500KB，500kb = 500*1024KB
   　　　　   uploadButtonText:&#39;图片上传&#39;,　　　　　　　　　　　　//在页面显示上传按钮
     　　　　 inputName: &#39;myFile&#39;,　　　　　　　　　　　　　　　　//在input标签中的name属性设置为myFile
   　　　　   messages:{　　　　　　　　　　　　　　　　　　　　　//设置的提示信息，包括大小类型等的操作
        　　　　  typeError:&#39;只允许jpeg,jpg,gif,png格式的图片文件{file}&#39;,
        　　　　  sizeError:&#39;文件大小不能超过{sizeLimit}。{file}&#39;,
       　　　　   emptyError:&#39;文件不可为空{file}&#39;,
         　　　　 onLeave:&#39;文件正在上传，离开将终止上传操作？&#39;
    　　　　  },
      　　　　showMessage:function(message){　　　　　　　　　　//显示信息
         　　 alert(message);
     　　　　 },
             // 设置返回从服务器反馈的error信息，不过我这里利用这个responseProperty属性反馈msg信息，
             // 具体的msg内容在服务中设置。
    　　　　  failedUploadTextDisplay: {
       　　　　 mode: &#39;custom&#39;,
      　　　　  maxChars: 40,
       　　　　 responseProperty: &#39;msg&#39;,
       　　　　 enableTooltip: true
    　　  }

  　　　  });
　　  })　　

　　&lt;/<span style="color:#8b008b;font-weight:bold">scripte</span>&gt;

&lt;/<span style="color:#8b008b;font-weight:bold">head</span>&gt;

&lt;<span style="color:#8b008b;font-weight:bold">body</span>&gt;

     &lt;<span style="color:#8b008b;font-weight:bold">fieldset</span>&gt;
           &lt;<span style="color:#8b008b;font-weight:bold">legend</span>&gt;&lt;<span style="color:#8b008b;font-weight:bold">span</span>&gt;您可以上传一张不超过500kb的图片&lt;/<span style="color:#8b008b;font-weight:bold">span</span>&gt;&lt;/<span style="color:#8b008b;font-weight:bold">legend</span>&gt;
            &lt;<span style="color:#8b008b;font-weight:bold">div</span>&gt;
                   &lt;<span style="color:#8b008b;font-weight:bold">div</span> <span style="color:#658b00">id</span>=<span style="color:#cd5555">&#34;thumbnail-fine-uploader&#34;</span>&gt;&lt;/<span style="color:#8b008b;font-weight:bold">div</span>&gt;  
             &lt;/<span style="color:#8b008b;font-weight:bold">div</span>&gt;
    &lt;/<span style="color:#8b008b;font-weight:bold">fieldset</span>&gt;

&lt;/<span style="color:#8b008b;font-weight:bold">body</span>&gt;

&lt;/<span style="color:#8b008b;font-weight:bold">html</span>&gt;
</code></pre></div><h2 id="三action-服务器端代码">三、Action 服务器端代码</h2>
<p>提示：我在项目中使用了 S2SH 框架，所以注意下自己写代码时候的区别。</p>
<div class="highlight"><pre style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4"><code class="language-java" data-lang="java"><span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">java.io.File</span>;
<span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">java.io.FileInputStream</span>;
<span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">java.io.FileOutputStream</span>;
<span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">java.io.InputStream</span>;
<span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">javax.servlet.http.HttpServletRequest</span>;
<span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">org.apache.struts2.ServletActionContext</span>;
<span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">org.hibernate.Hibernate</span>;

<span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">com.byg.entity.TableMsgService</span>;
<span style="color:#8b008b;font-weight:bold">import</span> <span style="color:#008b45;text-decoration:underline">com.byg.service.SendMessageService</span>;

<span style="color:#8b008b;font-weight:bold">public</span> <span style="color:#8b008b;font-weight:bold">class</span> <span style="color:#008b45;font-weight:bold">FileHandleAction</span> <span style="color:#8b008b;font-weight:bold">extends</span> SessionAction{

    <span style="color:#8b008b;font-weight:bold">private</span> SendMessageService service;

    <span style="color:#8b008b;font-weight:bold">public</span> <span style="color:#00688b;font-weight:bold">void</span> <span style="color:#008b45">setService</span>(SendMessageService service) {
        <span style="color:#8b008b;font-weight:bold">this</span>.<span style="color:#658b00">service</span> = service;
    }
    <span style="color:#228b22">// myFile属性，即刚才在声明fileuploader 对象时候设置的myFile属性。通过此属性接收file的Name
</span><span style="color:#228b22"></span>    <span style="color:#8b008b;font-weight:bold">private</span> String myFile;

    <span style="color:#8b008b;font-weight:bold">public</span> String <span style="color:#008b45">getMyFile</span>() {
        <span style="color:#8b008b;font-weight:bold">return</span> myFile;
    }
    <span style="color:#8b008b;font-weight:bold">public</span> <span style="color:#00688b;font-weight:bold">void</span> <span style="color:#008b45">setMyFile</span>(String myFile) {
        <span style="color:#8b008b;font-weight:bold">this</span>.<span style="color:#658b00">myFile</span> = myFile;
    }
    <span style="color:#228b22">// 用于返回json数据，即在刚才在fileuploader对象中的failedUploadTextDisplay
</span><span style="color:#228b22"></span>    <span style="color:#228b22">// 中设置的responseProperty属性，显示msg的信息
</span><span style="color:#228b22"></span>    <span style="color:#8b008b;font-weight:bold">private</span> String msg;

    <span style="color:#8b008b;font-weight:bold">public</span> String <span style="color:#008b45">getMsg</span>() {
        <span style="color:#8b008b;font-weight:bold">return</span> msg;
    }
    <span style="color:#8b008b;font-weight:bold">public</span> <span style="color:#00688b;font-weight:bold">void</span> <span style="color:#008b45">setMsg</span>(String msg) {
        <span style="color:#8b008b;font-weight:bold">this</span>.<span style="color:#658b00">msg</span> = msg;
    }
    <span style="color:#228b22">//check file size
</span><span style="color:#228b22"></span>    <span style="color:#228b22">/**
</span><span style="color:#228b22">     * upload image
</span><span style="color:#228b22">     */</span>
    <span style="color:#8b008b;font-weight:bold">public</span> String <span style="color:#008b45">uploadImage</span>(){
        <span style="color:#228b22">//声明request对象用于获取文件流
</span><span style="color:#228b22"></span>        HttpServletRequest request = ServletActionContext.<span style="color:#658b00">getRequest</span>();

        <span style="color:#8b008b;font-weight:bold">if</span>(<span style="color:#8b008b;font-weight:bold">this</span>.<span style="color:#658b00">getMyFile</span>()!=<span style="color:#8b008b;font-weight:bold">null</span>){        <span style="color:#228b22">//如果图片名不为空
</span><span style="color:#228b22"></span>
            File myFile = <span style="color:#8b008b;font-weight:bold">new</span> File(<span style="color:#8b008b;font-weight:bold">this</span>.<span style="color:#658b00">getMyFile</span>());　　<span style="color:#228b22">//用改文件名new 一个文件对象
</span><span style="color:#228b22"></span>
            <span style="color:#8b008b;font-weight:bold">try</span> {
                    InputStream is = request.<span style="color:#658b00">getInputStream</span>();    <span style="color:#228b22">//获取文件流
</span><span style="color:#228b22"></span>                    FileOutputStream fout = <span style="color:#8b008b;font-weight:bold">new</span> FileOutputStream(myFile);<span style="color:#228b22">//定义文件输出流
</span><span style="color:#228b22"></span>
                    <span style="color:#00688b;font-weight:bold">byte</span> b[] = <span style="color:#8b008b;font-weight:bold">new</span> <span style="color:#00688b;font-weight:bold">byte</span>[1000];

                    <span style="color:#00688b;font-weight:bold">int</span> n ;
                    <span style="color:#228b22">//从inputStream中把获取的文件流写入这个新new的文件对象中
</span><span style="color:#228b22"></span>                    <span style="color:#8b008b;font-weight:bold">while</span>((n=is.<span style="color:#658b00">read</span>(b))!=-1){

                        fout.<span style="color:#658b00">write</span>(b,0,n);
                    }
                    is.<span style="color:#658b00">close</span>();
                    fout.<span style="color:#658b00">flush</span>();
                    fout.<span style="color:#658b00">close</span>();
                    <span style="color:#228b22">// 我的Image对象的定义是Blob类型，所以这里我通过进一步的转化myFile
</span><span style="color:#228b22"></span>                    FileInputStream in = <span style="color:#8b008b;font-weight:bold">new</span> FileInputStream(myFile);
                    TableMsgService msgService = <span style="color:#8b008b;font-weight:bold">new</span> TableMsgService();
                    <span style="color:#228b22">//通过Hibernate的createBlob方法转化,然后设置我的image属性
</span><span style="color:#228b22"></span>                    msgService.<span style="color:#658b00">setImage</span>(Hibernate.<span style="color:#658b00">createBlob</span>(in));
                    <span style="color:#228b22">//最后保存包含这个Blob类型数据的对象，用的Hibernate框架　　
</span><span style="color:#228b22"></span>                    service.<span style="color:#658b00">save</span>(msgService);    <span style="color:#228b22">//save this object;
</span><span style="color:#228b22"></span>
                    msg = <span style="color:#cd5555">&#34;文件&#34;</span>+<span style="color:#8b008b;font-weight:bold">this</span>.<span style="color:#658b00">getMyFile</span>()+<span style="color:#cd5555">&#34;上传成功&#34;</span>;　<span style="color:#228b22">// msg 设置显示成功
</span><span style="color:#228b22"></span>
            }<span style="color:#8b008b;font-weight:bold">catch</span>(Exception e) {
                msg = <span style="color:#cd5555">&#34;文件&#34;</span>+<span style="color:#8b008b;font-weight:bold">this</span>.<span style="color:#658b00">getMyFile</span>()+<span style="color:#cd5555">&#34;上传失败&#34;</span>; <span style="color:#228b22">//如果异常 设置msg显示失败
</span><span style="color:#228b22"></span>                e.<span style="color:#658b00">printStackTrace</span>();
            }
        }

        <span style="color:#8b008b;font-weight:bold">return</span> <span style="color:#cd5555">&#34;succ&#34;</span>;

    }
}
</code></pre></div><h2 id="三strutsxml-的配置">三、Struts.xml 的配置</h2>
<div class="highlight"><pre style="background-color:#eed;-moz-tab-size:4;-o-tab-size:4;tab-size:4"><code class="language-xml" data-lang="xml">
<span style="color:#8b008b;font-weight:bold">&lt;struts&gt;</span>
    <span style="color:#8b008b;font-weight:bold">&lt;constant</span> <span style="color:#658b00">name=</span><span style="color:#cd5555">&#34;struts.il8n.encoding&#34;</span> <span style="color:#658b00">value=</span><span style="color:#cd5555">&#34;utf-8&#34;</span><span style="color:#8b008b;font-weight:bold">&gt;&lt;/constant&gt;</span>

    <span style="color:#8b008b;font-weight:bold">&lt;package</span> <span style="color:#658b00">name=</span><span style="color:#cd5555">&#34;test&#34;</span> <span style="color:#658b00">extends=</span><span style="color:#cd5555">&#34;json-default&#34;</span> <span style="color:#658b00">namespace=</span><span style="color:#cd5555">&#34;/service&#34;</span><span style="color:#8b008b;font-weight:bold">&gt;</span>
            // 我这里写的是spring配置的Action
　　        <span style="color:#8b008b;font-weight:bold">&lt;action</span> <span style="color:#658b00">name=</span><span style="color:#cd5555">&#34;uploadImage&#34;</span> <span style="color:#658b00">class=</span><span style="color:#cd5555">&#34;fileHandleAction&#34;</span> <span style="color:#658b00">method=</span><span style="color:#cd5555">&#34;uploadImage&#34;</span><span style="color:#8b008b;font-weight:bold">&gt;</span>　　
            <span style="color:#8b008b;font-weight:bold">&lt;result</span> <span style="color:#658b00">name=</span><span style="color:#cd5555">&#34;succ&#34;</span> <span style="color:#658b00">type=</span><span style="color:#cd5555">&#34;json&#34;</span><span style="color:#8b008b;font-weight:bold">/&gt;</span>　// 返回json数据，即msg属性的信息
        <span style="color:#8b008b;font-weight:bold">&lt;/action&gt;</span>
    <span style="color:#8b008b;font-weight:bold">&lt;/package&gt;</span>
<span style="color:#8b008b;font-weight:bold">&lt;/struts&gt;</span>

</code></pre></div><h2 id="四结语">四、结语</h2>
<p>fileuploader.js 这款插件还是很是强大的，支持进度条的显示，也可以自定义气样式，不过目前我还是没有了解很透这款插件。有时间好好琢磨。希望这篇文章可以对大家有需要的分享下。</p>
